    runtimeProviders: [runtimeProvider],
    tools: [registryTool],
    skills: [registrySkill],
    gateways: [gateway],
    buildingCapabilities: [capability],
    limit: 50,
    placeholderOnly: true,
    requestId: "req_registry",
    ...overrides
  };
}

function managementBody(overrides: Record<string, unknown> = {}) {
