import Fastify, { type FastifyInstance, type FastifyReply } from "fastify";
import cors from "@fastify/cors";
import {
  authenticateRequest,
  getPermissionsForSelectedProject,
  requestIdFor,
  requirePermission,
  requireProjectMembership,
  requireSelectedProject,
  sendError
} from "./auth.js";
import { createSeedStore, type ChatMessage, type SeedStore } from "./seed.js";

interface BuildServerOptions {
  store?: SeedStore;
}

interface ProjectParams {
  projectId: string;
}

interface LoginBody {
  email?: unknown;
  password?: unknown;
}

interface ChatBody {
  message?: unknown;
}

let messageSequence = 0;

function nextMessageId(): string {
  messageSequence += 1;
  return `msg_${String(messageSequence).padStart(6, "0")}`;
}

function bounded<T>(items: T[], limit: number): T[] {
  return items.slice(0, limit);
}

function boundedPlaceholderList<T>(items: T[], store: SeedStore): T[] {
  return bounded(items, store.maxListSize);
}

function isReply(value: unknown): value is FastifyReply {
  return typeof value === "object" && value !== null && "sent" in value;
}

function validateChatMessage(body: unknown): string | null {
  if (typeof body !== "object" || body === null || Array.isArray(body)) {
    return null;
  }

  const message = (body as ChatBody).message;
  if (typeof message !== "string") {
    return null;
  }

  const trimmed = message.trim();
  if (trimmed.length === 0 || trimmed.length > 1000) {
    return null;
  }

  return trimmed;
}

export function buildServer(options: BuildServerOptions = {}): FastifyInstance {
  const store = options.store ?? createSeedStore();
  messageSequence = 0;

  const app = Fastify({
    logger: false,
    genReqId: (() => {
      let sequence = 0;
      return () => {
        sequence += 1;
        return `req_${String(sequence).padStart(6, "0")}`;
      };
    })()
  });

  void app.register(cors, { origin: true });

  app.get("/health", async (request) => ({
    ok: true,
    service: "building-agent-api",
    requestId: requestIdFor(request)
  }));

  app.post<{ Body: LoginBody }>("/api/login", async (request, reply) => {
    const { email, password } = request.body ?? {};
    if (typeof email !== "string" || typeof password !== "string" || !email.trim() || !password) {
      return sendError(request, reply, 401, "auth_invalid", "Invalid credentials.");
    }

    const user = store.users.find((candidate) => candidate.email === email && candidate.password === password);
    if (!user) {
      return sendError(request, reply, 401, "auth_invalid", "Invalid credentials.");
    }

    const token = Object.entries(store.tokens).find(([, userId]) => userId === user.id)?.[0];
    if (!token) {
      return sendError(request, reply, 401, "auth_invalid", "Invalid credentials.");
    }

    store.sessionsByToken[token] = store.sessionsByToken[token] ?? { userId: user.id, selectedProjectId: null };

    return {
      token,
      user: { id: user.id, name: user.name },
      requestId: requestIdFor(request)
    };
  });

  app.get("/api/session", async (request, reply) => {
    const session = authenticateRequest(request, reply, store);
    if (isReply(session)) {
      return session;
    }

    return {
      session: {
        userId: session.userId,
        projectId: session.projectId,
        permissions: session.permissions
      },
      requestId: requestIdFor(request)
    };
  });

  app.get("/api/projects", async (request, reply) => {
    const session = authenticateRequest(request, reply, store);
    if (isReply(session)) {
      return session;
    }

    const memberships = store.memberships.filter((membership) => membership.userId === session.userId);
    const projects = bounded(memberships, store.maxListSize).flatMap((membership) => {
      const project = store.projects.find((candidate) => candidate.id === membership.projectId);
      return project ? [{ id: project.id, name: project.name, permissions: membership.permissions }] : [];
    });

    return { projects, limit: store.maxListSize, requestId: requestIdFor(request) };
  });

  app.get("/api/registry", async (request, reply) => {
    const session = authenticateRequest(request, reply, store);
    if (isReply(session)) {
      return session;
    }

    return {
      runtimeProviders: boundedPlaceholderList(store.runtimeProviders, store),
      tools: boundedPlaceholderList(store.tools, store),
      skills: boundedPlaceholderList(store.skills, store),
      gateways: boundedPlaceholderList(store.gateways, store),
      buildingCapabilities: boundedPlaceholderList(store.buildingCapabilities, store),
      limit: store.maxListSize,
      placeholderOnly: true,
      requestId: requestIdFor(request)
    };
  });

  app.get<{ Params: ProjectParams }>("/api/projects/:projectId/management", async (request, reply) => {
    const session = authenticateRequest(request, reply, store);
    if (isReply(session)) {
      return session;
    }

    const membership = requireProjectMembership(request, reply, store, session, request.params.projectId);
    if (isReply(membership)) {
      return membership;
    }

    const selected = requireSelectedProject(request, reply, session, request.params.projectId);
    if (isReply(selected)) {
      return selected;
    }

    const readable = requirePermission(request, reply, membership, "chat:read");
    if (isReply(readable)) {
      return readable;
    }

    const management = store.managementByProject[request.params.projectId] ?? {
      gateways: [],
      capabilities: [],
      tools: []
    };

    return {
      projectId: request.params.projectId,
      gateways: boundedPlaceholderList(management.gateways, store),
      capabilities: boundedPlaceholderList(management.capabilities, store),
      tools: boundedPlaceholderList(management.tools, store),
      limit: store.maxListSize,
      placeholderOnly: true,
      requestId: requestIdFor(request)
    };
  });

  app.post<{ Params: ProjectParams }>("/api/projects/:projectId/select", async (request, reply) => {
    const session = authenticateRequest(request, reply, store);
    if (isReply(session)) {
      return session;
    }

    const membership = requireProjectMembership(request, reply, store, session, request.params.projectId);
    if (isReply(membership)) {
      return membership;
    }

    const selectedSession = {
      userId: session.userId,
      selectedProjectId: request.params.projectId
    };
    store.sessionsByToken[session.token] = selectedSession;

    return {
      session: {
        userId: session.userId,
        projectId: request.params.projectId,
        permissions: getPermissionsForSelectedProject(store, selectedSession)
      },
      requestId: requestIdFor(request)
    };
  });

  app.get<{ Params: ProjectParams }>("/api/projects/:projectId/chat", async (request, reply) => {
    const session = authenticateRequest(request, reply, store);
    if (isReply(session)) {
      return session;
    }

    const membership = requireProjectMembership(request, reply, store, session, request.params.projectId);
    if (isReply(membership)) {
      return membership;
    }

    const selected = requireSelectedProject(request, reply, session, request.params.projectId);
    if (isReply(selected)) {
      return selected;
    }

    const readable = requirePermission(request, reply, membership, "chat:read");
    if (isReply(readable)) {
      return readable;
    }

    return {
      messages: bounded(store.messagesByProject[request.params.projectId] ?? [], store.maxListSize),
      limit: store.maxListSize,
      requestId: requestIdFor(request)
    };
  });

  app.post<{ Params: ProjectParams; Body: ChatBody }>("/api/projects/:projectId/chat", async (request, reply) => {
    const session = authenticateRequest(request, reply, store);
    if (isReply(session)) {
      return session;
    }

    const membership = requireProjectMembership(request, reply, store, session, request.params.projectId);
    if (isReply(membership)) {
      return membership;
    }

    const selected = requireSelectedProject(request, reply, session, request.params.projectId);
    if (isReply(selected)) {
      return selected;
    }

    const writable = requirePermission(request, reply, membership, "chat:write");
    if (isReply(writable)) {
      return writable;
    }

    const content = validateChatMessage(request.body);
    if (!content) {
      return sendError(request, reply, 422, "chat_invalid", "Chat message must be 1-1000 characters.");
    }

    const messages = store.messagesByProject[request.params.projectId] ?? [];
    const message: ChatMessage = {
      id: nextMessageId(),
      projectId: request.params.projectId,
      userId: session.userId,
      role: "user",
      content
    };
    messages.push(message);
    if (messages.length > store.maxChatMessages) {
      messages.splice(0, messages.length - store.maxChatMessages);
    }
    store.messagesByProject[request.params.projectId] = messages;

    return reply.status(201).send({ message, requestId: requestIdFor(request) });
  });

  app.setErrorHandler((error, request, reply) => {
    if (error.validation) {
      return sendError(request, reply, 422, "chat_invalid", "Request payload is invalid.");
    }

    request.log.error({ err: error, requestId: requestIdFor(request) }, "Unhandled API error");
    return sendError(request, reply, 500, "internal_error", "Unexpected API error.");
  });

  return app;
}

export interface ApiErrorDetail {
  code: string;
  message: string;
  requestId?: string | undefined;
}

export class ApiClientError extends Error {
  readonly code: string;
  readonly requestId: string | undefined;
  readonly status: number | undefined;

  constructor(detail: ApiErrorDetail, status?: number) {
    super(detail.message);
    this.name = "ApiClientError";
    this.code = detail.code;
    this.requestId = detail.requestId;
    this.status = status;
  }
}

export interface UserSummary {
  id: string;
  name: string;
}

export interface SessionSummary {
  userId: string;
  projectId: string | null;
  permissions: string[];
}

export interface ProjectSummary {
  id: string;
  name: string;
  permissions: string[];
}

export interface ChatMessage {
  id: string;
  projectId: string;
  userId: string;
  role: "user";
  content: string;
}

export interface LoginResponse {
  token: string;
  user: UserSummary;
  requestId: string;
}

export type PlaceholderStatus = "placeholder" | "mock" | "not_configured";

interface PlaceholderBase {
  id: string;
  name: string;
  status: PlaceholderStatus;
  description: string;
}

export interface RuntimeProviderSummary extends PlaceholderBase {
  kind: "llm" | "embedding" | "workflow";
}

export interface ToolSummary extends PlaceholderBase {
  category: "analysis" | "retrieval" | "building";
}

export interface SkillSummary extends PlaceholderBase {
  domain: "building" | "project" | "runtime";
}

export interface GatewaySummary extends PlaceholderBase {
  protocol: "http" | "mcp" | "local";
}

export interface BuildingCapabilitySummary extends PlaceholderBase {
  domain: "energy" | "safety" | "maintenance" | "planning";
}

export interface RegistryResponse {
  runtimeProviders: RuntimeProviderSummary[];
  tools: ToolSummary[];
  skills: SkillSummary[];
  gateways: GatewaySummary[];
  buildingCapabilities: BuildingCapabilitySummary[];
  limit: number;
  placeholderOnly: true;
  requestId: string;
}

export interface ProjectManagementResponse {
  projectId: string;
  gateways: GatewaySummary[];
  capabilities: BuildingCapabilitySummary[];
  tools: ToolSummary[];
  limit: number;
  placeholderOnly: true;
  requestId: string;
}

const API_BASE_URL = import.meta.env.VITE_API_BASE_URL ?? "";
const REQUEST_TIMEOUT_MS = 8000;
const PLACEHOLDER_STATUSES = new Set(["placeholder", "mock", "not_configured"]);
const RUNTIME_KINDS = new Set(["llm", "embedding", "workflow"]);
const TOOL_CATEGORIES = new Set(["analysis", "retrieval", "building"]);
const SKILL_DOMAINS = new Set(["building", "project", "runtime"]);
const GATEWAY_PROTOCOLS = new Set(["http", "mcp", "local"]);
const CAPABILITY_DOMAINS = new Set(["energy", "safety", "maintenance", "planning"]);

function apiUrl(path: string): string {
  return `${API_BASE_URL}${path}`;
}

function isRecord(value: unknown): value is Record<string, unknown> {
  return typeof value === "object" && value !== null && !Array.isArray(value);
}

function isStringIn<T extends string>(value: unknown, allowed: Set<string>): value is T {
  return typeof value === "string" && allowed.has(value);
}

function parseApiError(value: unknown): ApiErrorDetail | null {
  if (!isRecord(value) || !isRecord(value.error)) {
    return null;
  }
  const { code, message, requestId } = value.error;
  if (typeof code !== "string" || typeof message !== "string") {
    return null;
  }
  return { code, message, requestId: typeof requestId === "string" ? requestId : undefined };
}

function malformed(message = "The API returned an unreadable response."): ApiClientError {
  return new ApiClientError({ code: "api_malformed", message });
}

function unavailable(): ApiClientError {
  return new ApiClientError({ code: "api_unavailable", message: "Local API is unavailable. Check that the API dev server is running, then retry." });
}

async function readJson(response: Response): Promise<unknown> {
  try {
    return await response.json();
  } catch {
    throw malformed();
  }
}

async function requestJson(path: string, options: RequestInit = {}): Promise<unknown> {
  const controller = new AbortController();
  const timeoutId = window.setTimeout(() => controller.abort(), REQUEST_TIMEOUT_MS);

  try {
    const response = await fetch(apiUrl(path), {
      ...options,
      headers: {
        "content-type": "application/json",
        ...options.headers
      },
      signal: controller.signal
    });
    const payload = await readJson(response);
    if (!response.ok) {
      const detail = parseApiError(payload) ?? { code: "api_malformed", message: "The API returned an error in an unexpected format." };
      throw new ApiClientError(detail, response.status);
    }
    return payload;
  } catch (error) {
    if (error instanceof ApiClientError) {
      throw error;
    }
    throw unavailable();
  } finally {
    window.clearTimeout(timeoutId);
  }
}

function authHeaders(token: string): HeadersInit {
  return { authorization: `Bearer ${token}` };
}

function hasPlaceholderBase(value: Record<string, unknown>): value is Record<string, unknown> & PlaceholderBase {
  return typeof value.id === "string" && typeof value.name === "string" && typeof value.description === "string" && isStringIn<PlaceholderStatus>(value.status, PLACEHOLDER_STATUSES);
}

function parseRuntimeProvider(value: unknown): RuntimeProviderSummary | null {
  if (!isRecord(value) || !hasPlaceholderBase(value) || !isStringIn<RuntimeProviderSummary["kind"]>(value.kind, RUNTIME_KINDS)) {
    return null;
  }
  return { id: value.id, name: value.name, status: value.status, description: value.description, kind: value.kind };
}

function parseTool(value: unknown): ToolSummary | null {
  if (!isRecord(value) || !hasPlaceholderBase(value) || !isStringIn<ToolSummary["category"]>(value.category, TOOL_CATEGORIES)) {
    return null;
  }
  return { id: value.id, name: value.name, status: value.status, description: value.description, category: value.category };
}

function parseSkill(value: unknown): SkillSummary | null {
  if (!isRecord(value) || !hasPlaceholderBase(value) || !isStringIn<SkillSummary["domain"]>(value.domain, SKILL_DOMAINS)) {
    return null;
  }
  return { id: value.id, name: value.name, status: value.status, description: value.description, domain: value.domain };
}

function parseGateway(value: unknown): GatewaySummary | null {
  if (!isRecord(value) || !hasPlaceholderBase(value) || !isStringIn<GatewaySummary["protocol"]>(value.protocol, GATEWAY_PROTOCOLS)) {
    return null;
  }
  return { id: value.id, name: value.name, status: value.status, description: value.description, protocol: value.protocol };
}

function parseCapability(value: unknown): BuildingCapabilitySummary | null {
  if (!isRecord(value) || !hasPlaceholderBase(value) || !isStringIn<BuildingCapabilitySummary["domain"]>(value.domain, CAPABILITY_DOMAINS)) {
    return null;
  }
  return { id: value.id, name: value.name, status: value.status, description: value.description, domain: value.domain };
}

function parseArray<T>(value: unknown, parser: (item: unknown) => T | null, message: string): T[] {
  if (!Array.isArray(value)) {
    throw malformed(message);
  }
  return value.map((item) => {
    const parsed = parser(item);
    if (!parsed) {
      throw malformed(message);
    }
    return parsed;
  });
}

function assertPlaceholderMeta(payload: Record<string, unknown>, message: string): { limit: number; requestId: string } {
  if (typeof payload.limit !== "number" || payload.placeholderOnly !== true || typeof payload.requestId !== "string") {
    throw malformed(message);
  }
  return { limit: payload.limit, requestId: payload.requestId };
}

export async function login(email: string, password: string): Promise<LoginResponse> {
  const payload = await requestJson("/api/login", {
    method: "POST",
    body: JSON.stringify({ email, password })
  });
  if (!isRecord(payload) || typeof payload.token !== "string" || !isRecord(payload.user) || typeof payload.user.id !== "string" || typeof payload.user.name !== "string" || typeof payload.requestId !== "string") {
    throw malformed("Login returned an unexpected response.");
  }
  return { token: payload.token, user: { id: payload.user.id, name: payload.user.name }, requestId: payload.requestId };
}

export async function getSession(token: string): Promise<{ session: SessionSummary; requestId: string }> {
  const payload = await requestJson("/api/session", { headers: authHeaders(token) });
  if (!isRecord(payload) || !isRecord(payload.session) || typeof payload.session.userId !== "string" || !(typeof payload.session.projectId === "string" || payload.session.projectId === null) || !Array.isArray(payload.session.permissions) || typeof payload.requestId !== "string") {
    throw malformed("Session returned an unexpected response.");
  }
  return {
    session: {
      userId: payload.session.userId,
      projectId: payload.session.projectId,
      permissions: payload.session.permissions.filter((permission): permission is string => typeof permission === "string")
    },
    requestId: payload.requestId
  };
}

export async function listProjects(token: string): Promise<{ projects: ProjectSummary[]; requestId: string }> {
  const payload = await requestJson("/api/projects", { headers: authHeaders(token) });
  if (!isRecord(payload) || !Array.isArray(payload.projects) || typeof payload.requestId !== "string") {
    throw malformed("Projects returned an unexpected response.");
  }
  return {
    projects: payload.projects.flatMap((project): ProjectSummary[] => {
      if (!isRecord(project) || typeof project.id !== "string" || typeof project.name !== "string" || !Array.isArray(project.permissions)) {
        return [];
      }
      return [{ id: project.id, name: project.name, permissions: project.permissions.filter((permission): permission is string => typeof permission === "string") }];
    }),
    requestId: payload.requestId
  };
}

export async function selectProject(token: string, projectId: string): Promise<{ session: SessionSummary; requestId: string }> {
  const payload = await requestJson(`/api/projects/${encodeURIComponent(projectId)}/select`, {
    method: "POST",
    headers: authHeaders(token)
  });
  if (!isRecord(payload) || !isRecord(payload.session) || typeof payload.session.userId !== "string" || typeof payload.session.projectId !== "string" || !Array.isArray(payload.session.permissions) || typeof payload.requestId !== "string") {
    throw malformed("Project selection returned an unexpected response.");
  }
  return {
    session: {
      userId: payload.session.userId,
      projectId: payload.session.projectId,
      permissions: payload.session.permissions.filter((permission): permission is string => typeof permission === "string")
    },
    requestId: payload.requestId
  };
}

export async function getChat(token: string, projectId: string): Promise<{ messages: ChatMessage[]; requestId: string }> {
  const payload = await requestJson(`/api/projects/${encodeURIComponent(projectId)}/chat`, { headers: authHeaders(token) });
  if (!isRecord(payload) || !Array.isArray(payload.messages) || typeof payload.requestId !== "string") {
    throw malformed("Chat returned an unexpected response.");
  }
  return {
    messages: payload.messages.flatMap((message): ChatMessage[] => {
      if (!isRecord(message) || typeof message.id !== "string" || typeof message.projectId !== "string" || typeof message.userId !== "string" || message.role !== "user" || typeof message.content !== "string") {
        return [];
      }
      return [{ id: message.id, projectId: message.projectId, userId: message.userId, role: message.role, content: message.content }];
    }),
    requestId: payload.requestId
  };
}

export async function getRegistry(token: string): Promise<RegistryResponse> {
  const payload = await requestJson("/api/registry", { headers: authHeaders(token) });
  if (!isRecord(payload)) {
    throw malformed("Registry returned an unexpected response.");
  }
  const meta = assertPlaceholderMeta(payload, "Registry returned an unexpected response.");
  return {
    runtimeProviders: parseArray(payload.runtimeProviders, parseRuntimeProvider, "Registry returned unexpected runtime providers."),
    tools: parseArray(payload.tools, parseTool, "Registry returned unexpected tools."),
    skills: parseArray(payload.skills, parseSkill, "Registry returned unexpected skills."),
    gateways: parseArray(payload.gateways, parseGateway, "Registry returned unexpected gateways."),
    buildingCapabilities: parseArray(payload.buildingCapabilities, parseCapability, "Registry returned unexpected building capabilities."),
    limit: meta.limit,
    placeholderOnly: true,
    requestId: meta.requestId
  };
}

export async function getProjectManagement(token: string, projectId: string): Promise<ProjectManagementResponse> {
  const payload = await requestJson(`/api/projects/${encodeURIComponent(projectId)}/management`, { headers: authHeaders(token) });
  if (!isRecord(payload) || typeof payload.projectId !== "string") {
    throw malformed("Project management returned an unexpected response.");
  }
  const meta = assertPlaceholderMeta(payload, "Project management returned an unexpected response.");
  return {
    projectId: payload.projectId,
    gateways: parseArray(payload.gateways, parseGateway, "Project management returned unexpected gateways."),
    capabilities: parseArray(payload.capabilities, parseCapability, "Project management returned unexpected capabilities."),
    tools: parseArray(payload.tools, parseTool, "Project management returned unexpected tools."),
    limit: meta.limit,
    placeholderOnly: true,
    requestId: meta.requestId
  };
}

export async function sendChatMessage(token: string, projectId: string, message: string): Promise<{ message: ChatMessage; requestId: string }> {
  const payload = await requestJson(`/api/projects/${encodeURIComponent(projectId)}/chat`, {
    method: "POST",
    headers: authHeaders(token),
    body: JSON.stringify({ message })
  });
  if (!isRecord(payload) || !isRecord(payload.message) || typeof payload.message.id !== "string" || typeof payload.message.projectId !== "string" || typeof payload.message.userId !== "string" || payload.message.role !== "user" || typeof payload.message.content !== "string" || typeof payload.requestId !== "string") {
    throw malformed("Chat post returned an unexpected response.");
  }
  return {
    message: {
      id: payload.message.id,
      projectId: payload.message.projectId,
      userId: payload.message.userId,
      role: payload.message.role,
      content: payload.message.content
    },
    requestId: payload.requestId
  };
}

import { describe, expect, it } from "vitest";
import { buildServer } from "./server.js";

const token = "seed-token-ada";

function bearer(value = token) {
  return { authorization: `Bearer ${value}` };
}

describe("auth, session, and project contract", () => {
  it("exposes health without authentication and includes a request id", async () => {
    const app = buildServer();
    const response = await app.inject({ method: "GET", url: "/health" });

    expect(response.statusCode).toBe(200);
    expect(response.json()).toMatchObject({ ok: true, service: "building-agent-api" });
    expect(response.json().requestId).toMatch(/^req_/);
  });

  it("logs in a seeded user without exposing the token in logs", async () => {
    const app = buildServer();
    const response = await app.inject({
      method: "POST",
      url: "/api/login",
      payload: { email: "ada@example.test", password: "local-dev-password" }
    });

    expect(response.statusCode).toBe(200);
    expect(response.json()).toEqual({
      token,
      user: { id: "user_ada", name: "Ada Lovelace" },
      requestId: expect.stringMatching(/^req_/)
    });
  });

  it("rejects empty credentials with a canonical error", async () => {
    const app = buildServer();
    const response = await app.inject({
      method: "POST",
      url: "/api/login",
      payload: { email: "", password: "" }
    });

    expect(response.statusCode).toBe(401);
    expect(response.json()).toEqual({
      error: {
        code: "auth_invalid",
        message: "Invalid credentials.",
        requestId: expect.stringMatching(/^req_/)
      }
    });
  });

  it("rejects missing, malformed, and unknown bearer tokens", async () => {
    const app = buildServer();

    const missing = await app.inject({ method: "GET", url: "/api/session" });
    expect(missing.statusCode).toBe(401);
    expect(missing.json().error).toMatchObject({ code: "auth_missing" });

    const malformed = await app.inject({
      method: "GET",
      url: "/api/session",
      headers: { authorization: "Token definitely-not-bearer" }
    });
    expect(malformed.statusCode).toBe(401);
    expect(malformed.json().error).toMatchObject({ code: "auth_invalid" });

    const unknown = await app.inject({
      method: "GET",
      url: "/api/session",
      headers: bearer("unknown-token")
    });
    expect(unknown.statusCode).toBe(401);
    expect(unknown.json().error).toMatchObject({ code: "auth_invalid" });
  });

  it("returns session and bounded authorized projects for a valid token", async () => {
    const app = buildServer();

    const session = await app.inject({ method: "GET", url: "/api/session", headers: bearer() });
    expect(session.statusCode).toBe(200);
    expect(session.json()).toEqual({
      session: {
        userId: "user_ada",
        projectId: null,
        permissions: []
      },
      requestId: expect.stringMatching(/^req_/)
    });

    const projects = await app.inject({ method: "GET", url: "/api/projects", headers: bearer() });
    expect(projects.statusCode).toBe(200);
    expect(projects.json()).toEqual({
      projects: [
        { id: "project_alpha", name: "Alpha Build", permissions: ["chat:read", "chat:write"] },
        { id: "project_beta", name: "Beta Build", permissions: ["chat:read"] }
      ],
      limit: 50,
      requestId: expect.stringMatching(/^req_/)
    });
  });

  it("selects an authorized project and rejects a forbidden project", async () => {
    const app = buildServer();

    const selected = await app.inject({
      method: "POST",
      url: "/api/projects/project_alpha/select",
      headers: bearer()
    });
    expect(selected.statusCode).toBe(200);
    expect(selected.json()).toEqual({
      session: {
        userId: "user_ada",
        projectId: "project_alpha",
        permissions: ["chat:read", "chat:write"]
      },
      requestId: expect.stringMatching(/^req_/)
    });

    const forbidden = await app.inject({
      method: "POST",
      url: "/api/projects/project_gamma/select",
      headers: bearer()
    });
    expect(forbidden.statusCode).toBe(403);
    expect(forbidden.json().error).toMatchObject({ code: "project_forbidden" });
  });
});

import { describe, expect, it } from "vitest";
import { buildServer } from "./server.js";

const adaToken = "seed-token-ada";
const graceToken = "seed-token-grace";

function bearer(value: string) {
  return { authorization: `Bearer ${value}` };
}

describe("project-scoped chat contract", () => {
  it("requires auth and a matching selected project before reading chat", async () => {
    const app = buildServer();

    const unauthorized = await app.inject({ method: "GET", url: "/api/projects/project_alpha/chat" });
    expect(unauthorized.statusCode).toBe(401);
    expect(unauthorized.json().error).toMatchObject({ code: "auth_missing" });

    const notSelected = await app.inject({
      method: "GET",
      url: "/api/projects/project_alpha/chat",
      headers: bearer(adaToken)
    });
    expect(notSelected.statusCode).toBe(403);
    expect(notSelected.json().error).toMatchObject({ code: "project_not_selected" });
  });

  it("stores and returns chat messages only for the selected project", async () => {
    const app = buildServer();

    await app.inject({ method: "POST", url: "/api/projects/project_alpha/select", headers: bearer(adaToken) });
    const posted = await app.inject({
      method: "POST",
      url: "/api/projects/project_alpha/chat",
      headers: bearer(adaToken),
      payload: { message: "What should we build first?" }
    });

    expect(posted.statusCode).toBe(201);
    expect(posted.json()).toEqual({
      message: {
        id: "msg_000001",
        projectId: "project_alpha",
        userId: "user_ada",
        role: "user",
        content: "What should we build first?"
      },
      requestId: expect.stringMatching(/^req_/)
    });

    const alphaChat = await app.inject({
      method: "GET",
      url: "/api/projects/project_alpha/chat",
      headers: bearer(adaToken)
    });
    expect(alphaChat.statusCode).toBe(200);
    expect(alphaChat.json()).toEqual({
      messages: [posted.json().message],
      limit: 50,
      requestId: expect.stringMatching(/^req_/)
    });

    await app.inject({ method: "POST", url: "/api/projects/project_beta/select", headers: bearer(adaToken) });
    const betaChat = await app.inject({
      method: "GET",
      url: "/api/projects/project_beta/chat",
      headers: bearer(adaToken)
    });
    expect(betaChat.statusCode).toBe(200);
    expect(betaChat.json().messages).toEqual([]);
  });

  it("rejects chat writes without selected project, write permission, or valid body", async () => {
    const app = buildServer();

    const notSelected = await app.inject({
      method: "POST",
      url: "/api/projects/project_alpha/chat",
      headers: bearer(adaToken),
      payload: { message: "Hello" }
    });
    expect(notSelected.statusCode).toBe(403);
    expect(notSelected.json().error).toMatchObject({ code: "project_not_selected" });

    await app.inject({ method: "POST", url: "/api/projects/project_beta/select", headers: bearer(adaToken) });
    const noWrite = await app.inject({
      method: "POST",
      url: "/api/projects/project_beta/chat",
      headers: bearer(adaToken),
      payload: { message: "Should not write" }
    });
    expect(noWrite.statusCode).toBe(403);
    expect(noWrite.json().error).toMatchObject({ code: "project_forbidden" });

    await app.inject({ method: "POST", url: "/api/projects/project_alpha/select", headers: bearer(adaToken) });
    for (const payload of [{}, { message: "" }, { message: "   " }, { message: "x".repeat(1001) }, { text: "wrong shape" }]) {
      const invalid = await app.inject({
        method: "POST",
        url: "/api/projects/project_alpha/chat",
        headers: bearer(adaToken),
        payload
      });
      expect(invalid.statusCode).toBe(422);
      expect(invalid.json().error).toMatchObject({ code: "chat_invalid" });
    }
  });

  it("rechecks membership on every operation and isolates projects between users", async () => {
    const app = buildServer();

    await app.inject({ method: "POST", url: "/api/projects/project_alpha/select", headers: bearer(adaToken) });
    await app.inject({
      method: "POST",
      url: "/api/projects/project_alpha/chat",
      headers: bearer(adaToken),
      payload: { message: "Alpha-only context" }
    });

    const graceForbidden = await app.inject({
      method: "GET",
      url: "/api/projects/project_alpha/chat",
      headers: bearer(graceToken)
    });
    expect(graceForbidden.statusCode).toBe(403);
    expect(graceForbidden.json().error).toMatchObject({ code: "project_forbidden" });

    await app.inject({ method: "POST", url: "/api/projects/project_gamma/select", headers: bearer(graceToken) });
    const graceChat = await app.inject({
      method: "GET",
      url: "/api/projects/project_gamma/chat",
      headers: bearer(graceToken)
    });
    expect(graceChat.statusCode).toBe(200);
    expect(graceChat.json().messages).toEqual([]);
  });
});

import { FormEvent, useEffect, useMemo, useState } from "react";
import {
  ApiClientError,
  getChat,
  getProjectManagement,
  getRegistry,
  getSession,
  listProjects,
  login,
  selectProject,
  sendChatMessage,
  type BuildingCapabilitySummary,
  type ChatMessage,
  type GatewaySummary,
  type ProjectManagementResponse,
  type ProjectSummary,
  type RegistryResponse,
  type RuntimeProviderSummary,
  type SessionSummary,
  type SkillSummary,
  type ToolSummary,
  type UserSummary
} from "./api";

const STORAGE_KEY = "building-agent.session.v1";
type WorkspaceTab = "chat" | "registry" | "gateways" | "building";

interface StoredSession {
  token: string;
  user: UserSummary | null;
  projectId: string | null;
}

interface BannerState {
  tone: "error" | "info" | "success";
  title: string;
  message: string;
  code?: string | undefined;
  requestId?: string | undefined;
}

function readStoredSession(): StoredSession {
  try {
    const raw = window.localStorage.getItem(STORAGE_KEY);
    if (!raw) {
      return { token: "", user: null, projectId: null };
    }
    const parsed = JSON.parse(raw) as Partial<StoredSession>;
    return {
      token: typeof parsed.token === "string" ? parsed.token : "",
      user: parsed.user && typeof parsed.user.id === "string" && typeof parsed.user.name === "string" ? parsed.user : null,
      projectId: typeof parsed.projectId === "string" ? parsed.projectId : null
    };
  } catch {
    window.localStorage.removeItem(STORAGE_KEY);
    return { token: "", user: null, projectId: null };
  }
}

function storeSession(value: StoredSession): void {
  if (!value.token) {
    window.localStorage.removeItem(STORAGE_KEY);
    return;
  }
  window.localStorage.setItem(STORAGE_KEY, JSON.stringify(value));
}

function errorBanner(error: unknown, title: string): BannerState {
  if (error instanceof ApiClientError) {
    return { tone: "error", title, message: error.message, code: error.code, requestId: error.requestId };
  }
  return { tone: "error", title, message: "Something went wrong. Please retry." };
}

function isAuthFailure(error: unknown): boolean {
  return error instanceof ApiClientError && (error.status === 401 || error.code === "auth_invalid" || error.code === "auth_missing");
}

function Banner({ banner }: { banner: BannerState | null }) {
  if (!banner) {
    return null;
  }
  return (
    <section className={`banner banner-${banner.tone}`} role={banner.tone === "error" ? "alert" : "status"} aria-live="polite">
      <strong>{banner.title}</strong>
      <p>{banner.message}</p>
      {(banner.code || banner.requestId) ? (
        <p className="diagnostic-line">
          {banner.code ? <span>Code: {banner.code}</span> : null}
          {banner.requestId ? <span>Request: {banner.requestId}</span> : null}
        </p>
      ) : null}
    </section>
  );
}

function LoginScreen({ onLogin, busy }: { onLogin: (email: string, password: string) => Promise<void>; busy: boolean }) {
  const [email, setEmail] = useState("ada@example.test");
  const [password, setPassword] = useState("local-dev-password");
  const [validation, setValidation] = useState("");

  async function handleSubmit(event: FormEvent<HTMLFormElement>) {
    event.preventDefault();
    if (!email.trim() || !password) {
      setValidation("Enter the seeded email and password to continue.");
      return;
    }
    setValidation("");
    await onLogin(email.trim(), password);
  }

  return (
    <main className="auth-card" aria-labelledby="login-title">
      <p className="eyebrow">Local seeded access</p>
      <h1 id="login-title">Sign in to BuildingAgent</h1>
      <p className="muted">Use the development credentials from the README. Anonymous access is intentionally disabled.</p>
      <form className="stack" onSubmit={handleSubmit}>
        <label>
          Email
          <input autoComplete="username" value={email} onChange={(event) => setEmail(event.target.value)} />
        </label>
        <label>
          Password
          <input type="password" autoComplete="current-password" value={password} onChange={(event) => setPassword(event.target.value)} />
        </label>
        {validation ? <p className="field-error" role="alert">{validation}</p> : null}
        <button type="submit" disabled={busy}>{busy ? "Signing in…" : "Sign in"}</button>
      </form>
    </main>
  );
}

function ProjectScreen({ projects, onSelect, busy }: { projects: ProjectSummary[]; onSelect: (project: ProjectSummary) => Promise<void>; busy: boolean }) {
  return (
    <main className="workspace-card" aria-labelledby="projects-title">
      <p className="eyebrow">Project boundary</p>
      <h1 id="projects-title">Choose an authorized project</h1>
      <p className="muted">Only projects returned by the API for this seeded session are selectable.</p>
      <div className="project-grid">
        {projects.map((project) => (
          <article className="project-card" key={project.id}>
            <div>
              <h2>{project.name}</h2>
              <p>{project.id}</p>
              <p className="permissions">{project.permissions.join(" · ") || "No chat permissions"}</p>
            </div>
            <button type="button" onClick={() => void onSelect(project)} disabled={busy}>
              Select project
            </button>
          </article>
        ))}
