export default function App() {
  const initial = useMemo(readStoredSession, []);
  const [token, setToken] = useState(initial.token);
  const [user, setUser] = useState<UserSummary | null>(initial.user);
  const [session, setSession] = useState<SessionSummary | null>(null);
  const [projects, setProjects] = useState<ProjectSummary[]>([]);
  const [selectedProject, setSelectedProject] = useState<ProjectSummary | null>(null);
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [registry, setRegistry] = useState<RegistryResponse | null>(null);
  const [management, setManagement] = useState<ProjectManagementResponse | null>(null);
  const [activeTab, setActiveTab] = useState<WorkspaceTab>("chat");
  const [banner, setBanner] = useState<BannerState | null>(null);
  const [busy, setBusy] = useState(false);
  const [bootstrapping, setBootstrapping] = useState(Boolean(initial.token));

  function clearAuth(nextBanner?: BannerState) {
    setToken("");
    setUser(null);
    setSession(null);
    setProjects([]);
    setSelectedProject(null);
    setMessages([]);
    setRegistry(null);
    setManagement(null);
    setActiveTab("chat");
    storeSession({ token: "", user: null, projectId: null });
    setBanner(nextBanner ?? { tone: "info", title: "Signed out", message: "Sign in again to continue." });
  }

  async function loadManagementSurfaces(currentToken: string, projectId: string) {
    const [registryResponse, managementResponse] = await Promise.all([getRegistry(currentToken), getProjectManagement(currentToken, projectId)]);
    setRegistry(registryResponse);
    setManagement(managementResponse);
    return { registryResponse, managementResponse };
  }

  useEffect(() => {
    if (!token) {
      setBootstrapping(false);
      return;
    }

    let cancelled = false;
    async function bootstrap() {
      setBootstrapping(true);
      try {
        const [sessionResponse, projectResponse] = await Promise.all([getSession(token), listProjects(token)]);
        if (cancelled) {
          return;
        }
        setSession(sessionResponse.session);
        setProjects(projectResponse.projects);
        const restoredProject = projectResponse.projects.find((project) => project.id === sessionResponse.session.projectId) ?? null;
        setSelectedProject(restoredProject);
        if (restoredProject) {
          const [chatResponse, registryResponse, managementResponse] = await Promise.all([
            getChat(token, restoredProject.id),
            getRegistry(token),
            getProjectManagement(token, restoredProject.id)
          ]);
          if (!cancelled) {
            setMessages(chatResponse.messages);
            setRegistry(registryResponse);
            setManagement(managementResponse);
          }
        }
        setBanner(null);
      } catch (error) {
        if (!cancelled) {
          if (isAuthFailure(error)) {
            clearAuth(errorBanner(error, "Session expired"));
          } else {
            setBanner(errorBanner(error, "Could not load session"));
          }
        }
      } finally {
        if (!cancelled) {
          setBootstrapping(false);
        }
      }
    }

    void bootstrap();
    return () => {
      cancelled = true;
    };
  }, [token]);

  async function handleLogin(email: string, password: string) {
    setBusy(true);
    try {
      const response = await login(email, password);
      setToken(response.token);
      setUser(response.user);
      storeSession({ token: response.token, user: response.user, projectId: null });
      setRegistry(null);
      setManagement(null);
      setBanner({ tone: "success", title: "Signed in", message: `Welcome, ${response.user.name}.`, requestId: response.requestId });
    } catch (error) {
      setBanner(errorBanner(error, "Sign in failed"));
    } finally {
      setBusy(false);
    }
  }

  async function handleProjectSelect(project: ProjectSummary) {
    if (!token) {
      setBanner({ tone: "error", title: "Authentication required", message: "Sign in before selecting a project.", code: "auth_missing" });
      return;
    }
    setBusy(true);
    try {
      const selected = await selectProject(token, project.id);
      const [chat] = await Promise.all([getChat(token, project.id), loadManagementSurfaces(token, project.id)]);
      setSession(selected.session);
      setSelectedProject(project);
      setMessages(chat.messages);
      setActiveTab("chat");
      storeSession({ token, user, projectId: project.id });
      setBanner({ tone: "success", title: "Project selected", message: `${project.name} is now active. Placeholder registry and management surfaces loaded.`, requestId: selected.requestId });
    } catch (error) {
      if (isAuthFailure(error)) {
        clearAuth(errorBanner(error, "Session expired"));
      } else {
        setBanner(errorBanner(error, "Project selection failed"));
      }
    } finally {
      setBusy(false);
    }
  }

  async function handleSend(message: string) {
    if (!token || !selectedProject) {
      setBanner({ tone: "error", title: "Select a project first", message: "Chat is available only after authentication and project selection.", code: "project_not_selected" });
      return;
    }
    if (!message.trim()) {
      setBanner({ tone: "error", title: "Message required", message: "Enter a non-empty message before sending.", code: "chat_invalid" });
      return;
    }
    setBusy(true);
    try {
      const posted = await sendChatMessage(token, selectedProject.id, message.trim());
      setMessages((current) => [...current, posted.message]);
      setBanner({ tone: "success", title: "Message sent", message: "The API accepted the project-scoped message.", requestId: posted.requestId });
    } catch (error) {
      if (isAuthFailure(error)) {
        clearAuth(errorBanner(error, "Session expired"));
      } else {
        setBanner(errorBanner(error, "Chat message failed"));
      }
    } finally {
      setBusy(false);
    }
  }

  const authenticated = Boolean(token && user);

  return (
    <div className="app-shell">
      <header className="topbar">
        <div>
          <span className="brand-mark" aria-hidden="true">BA</span>
          <span className="brand-name">BuildingAgent</span>
        </div>
        {authenticated ? <button className="secondary" type="button" onClick={() => clearAuth()}>Sign out</button> : null}
      </header>
      <Banner banner={banner} />
      {bootstrapping ? <main className="workspace-card"><p>Checking your saved session…</p></main> : null}
      {!bootstrapping && !authenticated ? <LoginScreen onLogin={handleLogin} busy={busy} /> : null}
      {!bootstrapping && authenticated && !selectedProject ? <ProjectScreen projects={projects} onSelect={handleProjectSelect} busy={busy} /> : null}
      {!bootstrapping && authenticated && selectedProject ? <Workspace project={selectedProject} messages={messages} registry={registry} management={management} activeTab={activeTab} onTabChange={setActiveTab} onSend={handleSend} busy={busy} /> : null}
      {session ? <footer className="diagnostic-footer">Session project: {session.projectId ?? "none selected"}</footer> : null}
    </div>
  );
}

import type { FastifyReply, FastifyRequest } from "fastify";
import type { Permission, SeedMembership, SeedStore, SessionState } from "./seed.js";

export interface ApiSessionContext {
  token: string;
  userId: string;
  projectId: string | null;
  permissions: Permission[];
}

export interface ApiErrorBody {
  error: {
    code: string;
    message: string;
    requestId: string;
  };
}

export function requestIdFor(request: FastifyRequest): string {
  return String(request.id).startsWith("req_") ? String(request.id) : `req_${request.id}`;
}

export function errorResponse(
  request: FastifyRequest,
  code: string,
  message: string
): ApiErrorBody {
  return {
    error: {
      code,
      message,
      requestId: requestIdFor(request)
    }
  };
}

export function sendError(
  request: FastifyRequest,
  reply: FastifyReply,
  statusCode: number,
  code: string,
  message: string
): FastifyReply {
  return reply.status(statusCode).send(errorResponse(request, code, message));
}

function parseBearer(header: unknown): string | null {
  if (typeof header !== "string") {
    return null;
  }

  const parts = header.trim().split(/\s+/u);
  if (parts.length !== 2 || parts[0] !== "Bearer" || !parts[1]) {
    return null;
  }

  return parts[1];
}

function membershipFor(store: SeedStore, userId: string, projectId: string): SeedMembership | undefined {
  return store.memberships.find(
    (membership) => membership.userId === userId && membership.projectId === projectId
  );
}

export function getPermissionsForSelectedProject(store: SeedStore, session: SessionState): Permission[] {
  if (!session.selectedProjectId) {
    return [];
  }
  return membershipFor(store, session.userId, session.selectedProjectId)?.permissions ?? [];
}

export function authenticateRequest(
  request: FastifyRequest,
  reply: FastifyReply,
  store: SeedStore
): ApiSessionContext | FastifyReply {
  const authorization = request.headers.authorization;
  if (authorization === undefined) {
    return sendError(request, reply, 401, "auth_missing", "Missing bearer token.");
  }

  const token = parseBearer(authorization);
  if (!token) {
    return sendError(request, reply, 401, "auth_invalid", "Invalid bearer token.");
  }

  const userId = store.tokens[token];
  if (!userId) {
    return sendError(request, reply, 401, "auth_invalid", "Invalid bearer token.");
  }

  const session = store.sessionsByToken[token] ?? { userId, selectedProjectId: null };
  store.sessionsByToken[token] = session;

  return {
    token,
    userId,
    projectId: session.selectedProjectId,
    permissions: getPermissionsForSelectedProject(store, session)
  };
}

export function requireProjectMembership(
  request: FastifyRequest,
  reply: FastifyReply,
  store: SeedStore,
  session: ApiSessionContext,
  projectId: string
): SeedMembership | FastifyReply {
  const projectExists = store.projects.some((project) => project.id === projectId);
  const membership = membershipFor(store, session.userId, projectId);

  if (!projectExists || !membership) {
    return sendError(request, reply, 403, "project_forbidden", "Project is not available for this session.");
  }

  return membership;
}

export function requireSelectedProject(
  request: FastifyRequest,
  reply: FastifyReply,
  session: ApiSessionContext,
  projectId: string
): true | FastifyReply {
  if (session.projectId !== projectId) {
    return sendError(request, reply, 403, "project_not_selected", "Select this project before using project resources.");
  }

  return true;
}

export function requirePermission(
  request: FastifyRequest,
  reply: FastifyReply,
  membership: SeedMembership,
  permission: Permission
): true | FastifyReply {
  if (!membership.permissions.includes(permission)) {
    return sendError(request, reply, 403, "project_forbidden", "Project permission is required.");
  }

  return true;
}

