    await user.click(screen.getByRole("button", { name: /select project/i }));

    const alert = await screen.findByRole("alert");
    expect(alert).toHaveTextContent("registry_unavailable");
    expect(alert).toHaveTextContent("req_registry_fail");
    expect(screen.getByRole("heading", { name: /choose an authorized project/i })).toBeInTheDocument();

    installBaseFetch({ management: apiError("project_forbidden", "Project management denied.", 403, "req_management_fail") });
    await user.click(screen.getByRole("button", { name: /select project/i }));
    const secondAlert = await screen.findByRole("alert");
    expect(secondAlert).toHaveTextContent("project_forbidden");
    expect(secondAlert).toHaveTextContent("req_management_fail");
    expect(screen.getByRole("heading", { name: /choose an authorized project/i })).toBeInTheDocument();
    expect(window.localStorage.getItem("building-agent.session.v1")).toContain("seed-token-ada");
  });

  it("surfaces malformed registry and management payloads as api_malformed and supports empty placeholder lists", async () => {
    installBaseFetch({ registry: jsonResponse(registryBody({ placeholderOnly: undefined })) });
    const user = userEvent.setup();
    const { unmount } = render(<App />);
    await user.click(screen.getByRole("button", { name: /sign in/i }));
    await screen.findByRole("heading", { name: /choose an authorized project/i });
    await user.click(screen.getByRole("button", { name: /select project/i }));
    expect(await screen.findByRole("alert")).toHaveTextContent("api_malformed");
    unmount();

    window.localStorage.clear();
    vi.unstubAllGlobals();
    installBaseFetch({ management: jsonResponse(managementBody({ gateways: [{ ...gateway, protocol: "smtp" }] })) });
    render(<App />);
    await user.click(screen.getByRole("button", { name: /sign in/i }));
    await screen.findByRole("heading", { name: /choose an authorized project/i });
    await user.click(screen.getByRole("button", { name: /select project/i }));
    expect(await screen.findByRole("alert")).toHaveTextContent("api_malformed");

    vi.unstubAllGlobals();
    installBaseFetch({ registry: jsonResponse(registryBody({ runtimeProviders: [], tools: [], skills: [], gateways: [], buildingCapabilities: [] })), management: jsonResponse(managementBody({ gateways: [], capabilities: [], tools: [] })) });
    await user.click(screen.getByRole("button", { name: /select project/i }));
    await screen.findByRole("heading", { name: /alpha build workspace/i });
    await user.click(screen.getByRole("button", { name: /platform registry/i }));
    expect(screen.getByText(/no runtime provider placeholders returned/i)).toBeInTheDocument();
    await user.click(screen.getByRole("button", { name: /gateways/i }));
    expect(screen.getByText(/no project gateway placeholders returned/i)).toBeInTheDocument();
  });
});

    setMessages([]);
    setRegistry(null);
    setManagement(null);
    setActiveTab("chat");
    storeSession({ token: "", user: null, projectId: null });
    setBanner(nextBanner ?? { tone: "info", title: "Signed out", message: "Sign in again to continue." });
  }

  async function loadManagementSurfaces(currentToken: string, projectId: string) {
    const [registryResponse, managementResponse] = await Promise.all([getRegistry(currentToken), getProjectManagement(currentToken, projectId)]);
    setRegistry(registryResponse);
    setManagement(managementResponse);
    return { registryResponse, managementResponse };
  }

  useEffect(() => {
    if (!token) {
      setBootstrapping(false);
      return;
    }

    let cancelled = false;
    async function bootstrap() {
      setBootstrapping(true);
      try {
        const [sessionResponse, projectResponse] = await Promise.all([getSession(token), listProjects(token)]);
        if (cancelled) {
          return;
        }
        setSession(sessionResponse.session);
        setProjects(projectResponse.projects);
        const restoredProject = projectResponse.projects.find((project) => project.id === sessionResponse.session.projectId) ?? null;
        setSelectedProject(restoredProject);
        if (restoredProject) {
          const [chatResponse, registryResponse, managementResponse] = await Promise.all([
            getChat(token, restoredProject.id),
            getRegistry(token),
            getProjectManagement(token, restoredProject.id)
          ]);
          if (!cancelled) {
            setMessages(chatResponse.messages);
            setRegistry(registryResponse);
            setManagement(managementResponse);
          }
        }
        setBanner(null);
      } catch (error) {
        if (!cancelled) {
          if (isAuthFailure(error)) {
            clearAuth(errorBanner(error, "Session expired"));
          } else {
            setBanner(errorBanner(error, "Could not load session"));
          }
        }
      } finally {
        if (!cancelled) {
          setBootstrapping(false);
        }
      }
    }

    void bootstrap();
    return () => {
      cancelled = true;
    };
  }, [token]);

  async function handleLogin(email: string, password: string) {
    setBusy(true);
    try {
      const response = await login(email, password);
      setToken(response.token);
      setUser(response.user);
      storeSession({ token: response.token, user: response.user, projectId: null });
      setRegistry(null);
      setManagement(null);
      setBanner({ tone: "success", title: "Signed in", message: `Welcome, ${response.user.name}.`, requestId: response.requestId });
    } catch (error) {
      setBanner(errorBanner(error, "Sign in failed"));
    } finally {
      setBusy(false);
    }
  }

  async function handleProjectSelect(project: ProjectSummary) {
    if (!token) {
      setBanner({ tone: "error", title: "Authentication required", message: "Sign in before selecting a project.", code: "auth_missing" });
      return;
    }
    setBusy(true);
    try {
      const selected = await selectProject(token, project.id);
      const [chat] = await Promise.all([getChat(token, project.id), loadManagementSurfaces(token, project.id)]);
      setSession(selected.session);
      setSelectedProject(project);
      setMessages(chat.messages);
      setActiveTab("chat");
      storeSession({ token, user, projectId: project.id });
      setBanner({ tone: "success", title: "Project selected", message: `${project.name} is now active. Placeholder registry and management surfaces loaded.`, requestId: selected.requestId });
    } catch (error) {
      if (isAuthFailure(error)) {
        clearAuth(errorBanner(error, "Session expired"));
      } else {
        setBanner(errorBanner(error, "Project selection failed"));
      }
    } finally {
      setBusy(false);
    }
  }

  async function handleSend(message: string) {
    if (!token || !selectedProject) {
      setBanner({ tone: "error", title: "Select a project first", message: "Chat is available only after authentication and project selection.", code: "project_not_selected" });
      return;
    }
    if (!message.trim()) {
      setBanner({ tone: "error", title: "Message required", message: "Enter a non-empty message before sending.", code: "chat_invalid" });
      return;
    }
    setBusy(true);
    try {
      const posted = await sendChatMessage(token, selectedProject.id, message.trim());
      setMessages((current) => [...current, posted.message]);
      setBanner({ tone: "success", title: "Message sent", message: "The API accepted the project-scoped message.", requestId: posted.requestId });
    } catch (error) {
      if (isAuthFailure(error)) {
        clearAuth(errorBanner(error, "Session expired"));
      } else {
        setBanner(errorBanner(error, "Chat message failed"));
      }
    } finally {
      setBusy(false);
    }
  }

  const authenticated = Boolean(token && user);

  return (
    <div className="app-shell">
      <header className="topbar">
        <div>
          <span className="brand-mark" aria-hidden="true">BA</span>
          <span className="brand-name">BuildingAgent</span>
        </div>
        {authenticated ? <button className="secondary" type="button" onClick={() => clearAuth()}>Sign out</button> : null}
      </header>
      <Banner banner={banner} />
      {bootstrapping ? <main className="workspace-card"><p>Checking your saved session…</p></main> : null}
      {!bootstrapping && !authenticated ? <LoginScreen onLogin={handleLogin} busy={busy} /> : null}
      {!bootstrapping && authenticated && !selectedProject ? <ProjectScreen projects={projects} onSelect={handleProjectSelect} busy={busy} /> : null}
      {!bootstrapping && authenticated && selectedProject ? <Workspace project={selectedProject} messages={messages} registry={registry} management={management} activeTab={activeTab} onTabChange={setActiveTab} onSend={handleSend} busy={busy} /> : null}
      {session ? <footer className="diagnostic-footer">Session project: {session.projectId ?? "none selected"}</footer> : null}
    </div>
  );
}

